def longest_song_title(song_titles):
    return max(song_titles, key=lambda title: len(title.split()))

# Example usage:
songs = ["Wot Cher! Knocked 'em in the Old Kent Road", "The Future Mrs. 'Awkins", "Appy 'Ampstead", "My Old Dutch"]
print(longest_song_title(songs))  # Output: "Wot Cher! Knocked 'em in the Old Kent Road"
